import { createItem, readItems, updateItem } from '@directus/sdk'
import { directus } from '@/lib/directus'
import type { Product, ProductSample, ProductSubmission, RevisionRequest } from '@/lib/types'
import type { BusinessUnit } from '@/domain/products/types'
import { PRODUCT_SUMMARY_FIELDS } from '@/features/pipeline/api'

export interface WorkflowFetchOpts {
  search?: string
  businessUnit?: BusinessUnit
  limit?: number
}

const USER_FIELDS = ['id', 'first_name', 'last_name', 'email', 'avatar'] as const
const FILE_FIELDS = ['id', 'filename_download', 'title', 'type'] as const

function unitValues(unit?: BusinessUnit): string[] | null {
  if (!unit || unit === 'Unknown') return null
  if (unit === 'Licensed') return ['POP', 'POP Creations']
  if (unit === 'Generic') return ['Spruce', 'Spruce Line']
  return ['Software']
}

function productUnitFilter(unit?: BusinessUnit) {
  const values = unitValues(unit)
  return values ? [{ product: { business_unit: { _in: values } } }] : []
}

function directUnitFilter(unit?: BusinessUnit) {
  const values = unitValues(unit)
  return values ? [{ business_unit: { _in: values } }] : []
}

function submissionSearchFilter(search?: string) {
  const q = search?.trim()
  if (!q) return []
  return [{
    _or: [
      { product: { code: { _icontains: q } } },
      { product: { name: { _icontains: q } } },
      { project: { title: { _icontains: q } } },
      { notes: { _icontains: q } },
      { body: { _icontains: q } },
      { response_summary: { _icontains: q } },
      { portal_reference: { _icontains: q } },
      { brand_assurance_number: { _icontains: q } },
    ],
  }]
}

function sampleSearchFilter(search?: string) {
  const q = search?.trim()
  if (!q) return []
  return [{
    _or: [
      { product: { code: { _icontains: q } } },
      { product: { name: { _icontains: q } } },
      { project: { title: { _icontains: q } } },
      { notes: { _icontains: q } },
      { revision_reason: { _icontains: q } },
    ],
  }]
}

function revisionSearchFilter(search?: string) {
  const q = search?.trim()
  if (!q) return []
  return [{
    _or: [
      { product: { code: { _icontains: q } } },
      { product: { name: { _icontains: q } } },
      { project: { title: { _icontains: q } } },
      { body: { _icontains: q } },
      { requested_by_external: { _icontains: q } },
      { resolution_note: { _icontains: q } },
    ],
  }]
}

export const PRODUCT_CONTEXT_FIELDS = [
  'id',
  'code',
  'name',
  'description',
  'priority',
  'business_unit',
  'lifecycle_state',
  'next_action',
  'waiting_on',
  'blocker_reason',
  'risk_level',
  'on_shelf_date',
  'pps_requested_date',
  'pi_status',
  'brand_assurance_number',
  'closure_reason',
  'cover_url',
  'clickup_due_at',
  { stage: ['id', 'name'] },
  { licensor: ['id', 'name'] },
  { property: ['id', 'name'] },

  { property: ['id', 'name'] },
  { product_type: ['id', 'name'] },
  { factory: ['id', 'name'] },
  { project: ['id', 'title', 'status', 'business_unit', 'on_shelf_date', { retailer: ['id', 'name'] }, { buyer: ['id', 'name', 'samples_required'] }] },
  { design: ['id', 'name', 'status', 'theme', 'thumbnail_url'] },
] as const

export async function fetchSubmissions(opts: WorkflowFetchOpts = {}): Promise<ProductSubmission[]> {
  const { limit = 300 } = opts
  return directus.request(
    readItems('product_submission', {
      fields: [
        'id',
        'business_unit',
        'submission_type',
        'recipient_type',
        'submitted_at',
        'expected_response_at',
        'status',
        'response_at',
        'response_summary',
        'brand_assurance_number',
        'portal_url',
        'portal_reference',
        'revision_required',
        'notes',
        { product: PRODUCT_CONTEXT_FIELDS },
        { project: ['id', 'title', 'business_unit', { retailer: ['id', 'name'] }, { buyer: ['id', 'name'] }] },
        { licensor: ['id', 'name'] },
        { submitted_by: USER_FIELDS },
        { brand_assurance_file: FILE_FIELDS },
        { revision: ['id', 'status', 'source', 'due_at'] },
      ] as never,
      filter: { _and: [...directUnitFilter(opts.businessUnit), ...submissionSearchFilter(opts.search)] } as never,
      sort: ['expected_response_at', '-submitted_at'],
      limit,
    }),
  ) as Promise<ProductSubmission[]>
}

export async function fetchSamples(opts: WorkflowFetchOpts = {}): Promise<ProductSample[]> {
  const { limit = 300 } = opts
  return directus.request(
    readItems('product_sample', {
      fields: [
        'id',
        'sample_type',
        'requested_at',
        'expected_at',
        'received_at',
        'sent_to_buyer_at',
        'sent_to_licensor_at',
        'status',
        'photo_urls',
        'notes',
        'revision_required',
        'revision_reason',
        { product: PRODUCT_CONTEXT_FIELDS },
        { project: ['id', 'title', 'business_unit', { retailer: ['id', 'name'] }, { buyer: ['id', 'name'] }] },
        { factory: ['id', 'name', 'china_team_contact'] },
        { requested_by: USER_FIELDS },
        { primary_photo: FILE_FIELDS },
        { revision: ['id', 'status', 'source', 'due_at'] },
      ] as never,
      filter: { _and: [...productUnitFilter(opts.businessUnit), ...sampleSearchFilter(opts.search)] } as never,
      sort: ['expected_at', '-requested_at'],
      limit,
    }),
  ) as Promise<ProductSample[]>
}

export async function fetchRevisions(opts: WorkflowFetchOpts = {}): Promise<RevisionRequest[]> {
  const { limit = 300 } = opts
  return directus.request(
    readItems('revision_request', {
      fields: [
        'id',
        'object_collection',
        'object_id',
        'source',
        'requested_by_external',
        'requested_at',
        'due_at',
        'status',
        'body',
        'resolved_at',
        'resolution_note',
        { product: PRODUCT_CONTEXT_FIELDS },
        { project: ['id', 'title', 'business_unit', { retailer: ['id', 'name'] }, { buyer: ['id', 'name'] }] },
        { design: ['id', 'name', 'business_unit', 'status', 'theme', 'thumbnail_url'] },
        { submission: ['id', 'submission_type', 'status', 'expected_response_at'] },
        { requested_by_user: USER_FIELDS },
        { assigned_to: USER_FIELDS },
        { markup_file: FILE_FIELDS },
      ] as never,
      filter: { _and: [...productUnitFilter(opts.businessUnit), ...revisionSearchFilter(opts.search)] } as never,
      sort: ['due_at', '-requested_at'],
      limit,
    }),
  ) as Promise<RevisionRequest[]>
}

export async function fetchLifecycleOwnedProducts(userId: string, roleId: string | null): Promise<Product[]> {
  const ownership = roleId
    ? { _or: [{ next_owner_user: { _eq: userId } }, { next_owner_role: { _eq: roleId } }] }
    : { next_owner_user: { _eq: userId } }
  return directus.request(
    readItems('product', {
      fields: PRODUCT_SUMMARY_FIELDS,
      filter: ownership as never,
      limit: -1,
    }),
  ) as Promise<Product[]>
}

export async function fetchAssignedRevisions(userId: string): Promise<RevisionRequest[]> {
  return directus.request(
    readItems('revision_request', {
      fields: [
        'id',
        'source',
        'requested_at',
        'due_at',
        'status',
        'body',
        { product: PRODUCT_CONTEXT_FIELDS },
        { assigned_to: USER_FIELDS },
      ] as never,
      filter: {
        _and: [
          { assigned_to: { _eq: userId } },
          { status: { _nin: ['resolved', 'accepted', 'rejected', 'canceled'] } },
        ],
      } as never,
      sort: ['due_at', '-requested_at'],
      limit: -1,
    }),
  ) as Promise<RevisionRequest[]>
}

function relationId(value: unknown): string | null {
  if (!value) return null
  if (typeof value === 'string') return value
  if (typeof value === 'object' && 'id' in value && typeof value.id === 'string') return value.id
  return null
}

function businessUnitValue(product: Product): string | null {
  if (product.business_unit === 'Licensed') return 'POP Creations'
  if (product.business_unit === 'Generic') return 'Spruce Line'

import { useEffect, useMemo, useState } from 'react'
import { ArrowRight, ExternalLink, FileCheck2, Send, UserRound } from 'lucide-react'
import { productToSummary } from '@/domain/products/adapters'
import { useAppState } from '@/lib/appState'
import type { DirectusUser, Product, ProductSubmission } from '@/lib/types'
import { fetchSubmissions, updateSubmissionStatus } from '@/features/workflow/api'

function titleCase(value: string | null | undefined) {
  return (value ?? 'unknown').replaceAll('_', ' ').replace(/\b\w/g, (c) => c.toUpperCase())
}

function formatDate(iso: string | null | undefined) {
  if (!iso) return 'No date'
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

function relationName(value: unknown): string | null {
  if (!value || typeof value === 'string') return null
  if (typeof value === 'object' && 'name' in value && typeof value.name === 'string') return value.name
  if (typeof value === 'object' && 'title' in value && typeof value.title === 'string') return value.title
  return null
}

function userName(value: string | DirectusUser | null | undefined) {
  if (!value || typeof value === 'string') return null
  return [value.first_name, value.last_name].filter(Boolean).join(' ') || value.email
}

function productObject(row: ProductSubmission): Product | null {
  return row.product && typeof row.product === 'object' ? row.product : null
}

const STATUS_STYLE: Record<string, { bg: string; color: string }> = {
  ready: { bg: '#DEEBFB', color: '#2563A8' },
  submitted: { bg: '#FBEBD3', color: '#9A6400' },
  waiting: { bg: '#FBEBD3', color: '#9A6400' },
  changes_requested: { bg: '#FBE2D8', color: '#9E3B1C' },
  approved: { bg: '#D8EFE7', color: '#14745D' },
  rejected: { bg: '#F6CDBC', color: '#9E3B1C' },
}

function statusStyle(status: string | null | undefined) {
  return STATUS_STYLE[status ?? ''] ?? { bg: '#EEF1F6', color: '#5A6883' }
}

export function SubmissionsPage() {
  const { businessUnit, searchQuery } = useAppState()
  const [rows, setRows] = useState<ProductSubmission[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let active = true
    fetchSubmissions({ businessUnit, search: searchQuery })
      .then((next) => { if (active) setRows(next) })
      .catch((error) => {
        console.error(error)
        if (active) setRows([])
      })
      .finally(() => { if (active) setLoading(false) })
    return () => { active = false }
  }, [businessUnit, searchQuery])

  const groups = useMemo(() => {
    const map = new Map<string, ProductSubmission[]>()
    for (const row of rows) {
      const key = titleCase(row.status)
      ;(map.get(key) ?? map.set(key, []).get(key)!).push(row)
    }
    return [...map.entries()]
  }, [rows])

  if (loading) {
    return <div className="flex h-full items-center justify-center text-sm" style={{ color: '#94A0B5' }}>Loading submissions...</div>
  }

  return (
    <div className="h-full overflow-y-auto bg-white">
      <div className="mx-auto flex max-w-[1480px] flex-col gap-5 px-7 py-6">
        <div>
          <h1 className="text-[22px] font-extrabold leading-tight" style={{ color: '#1B2840' }}>Submissions</h1>
          <p className="mt-1 text-[13.5px]" style={{ color: '#5A6883' }}>
            Internal reviews, licensor submissions, buyer submissions, PPS, packaging, and production approvals
          </p>
        </div>

        {rows.length === 0 ? (
          <EmptyState label="No submissions match this filter yet." />
        ) : (
          <div className="space-y-6">
            {groups.map(([status, items]) => (
              <section key={status}>
                <GroupHeader label={status} count={items.length} />
                <div className="overflow-hidden rounded-lg border" style={{ borderColor: '#EAEEF5' }}>
                  <table className="w-full text-left">
                    <thead>
                      <tr style={{ borderBottom: '1px solid #EAEEF5' }}>
                        {(['Product', 'Type', 'Recipient', 'Submitted', 'Expected', 'Proof', 'Revision', 'Action'] as const).map((h) => (
                          <th key={h} className="bg-white px-4 py-3 text-[11px] font-bold uppercase tracking-[0.04em]" style={{ color: '#94A0B5', width: h === 'Product' ? '30%' : undefined }}>{h}</th>
                        ))}
                      </tr>

import { readItems, updateItem } from '@directus/sdk'
import { directus } from '@/lib/directus'
import type { Product, Stage } from '@/lib/types'

export async function setProductStage(productId: string, stageId: string | null) {
  return directus.request(updateItem('product', productId, { stage: stageId }))
}

export async function fetchStages(): Promise<Stage[]> {
  return directus.request(
    readItems('stage', { sort: ['stage_order'], limit: -1 }),
  ) as Promise<Stage[]>
}

// First slice loads a capped page of products; filtering/pagination comes next.
export async function fetchProducts(limit = 500): Promise<Product[]> {
  return directus.request(
    readItems('product', {
      fields: [
        'id',
        'code',
        'name',
        'business_unit',
        'on_shelf_date',
        'pi_status',
        'cover_url',
        { stage: ['id', 'name'] },
        { retailer: ['id', 'name'] },
        { licensor: ['id', 'name'] },
      ],
      limit,
    }),
  ) as Promise<Product[]>
}

// Assignee membership for the loaded products (sparse), for the Assignee filter.
export async function fetchAssigneeMap() {
  const rows = (await directus.request(
    readItems('product_assignee', {
      fields: ['product', { directus_user: ['id'] }] as never,
      limit: -1,
    }),
  )) as unknown as Array<{ product: string; directus_user: { id: string } | string }>
  const map = new Map<string, Set<string>>()
  for (const r of rows) {
    const uid = typeof r.directus_user === 'string' ? r.directus_user : r.directus_user?.id
    if (!r.product || !uid) continue
    if (!map.has(r.product)) map.set(r.product, new Set())
    map.get(r.product)!.add(uid)
  }
  return map
}

export function stageId(p: Product): string | null {
  if (!p.stage) return null
  return typeof p.stage === 'string' ? p.stage : p.stage.id
}

import { useEffect, useMemo, useRef, useState } from 'react'
import {
  DndContext,
  DragOverlay,
  PointerSensor,
  useDroppable,
  useDraggable,
  useSensor,
  useSensors,
  type DragEndEvent,
  type DragStartEvent,
} from '@dnd-kit/core'
import { CSS } from '@dnd-kit/utilities'
